@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftAsync" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightAsync" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<string> OnMoveRequested { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task MoveLeftAsync()
    {
        IsMoving = true;
        await OnMoveRequested.InvokeAsync("left");
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task MoveRightAsync()
    {
        IsMoving = true;
        await OnMoveRequested.InvokeAsync("right");
        IsMoving = false;
    }
}

@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title"
                       @bind="Title" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                       @bind="Assignee" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="SaveAsync" disabled="@IsSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(Error))
            {
                <div class="text-danger small mt-1">@Error</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? Error;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async System.Threading.Tasks.Task SaveAsync()
    {
        if (string.IsNullOrWhiteSpace(Title))
        {
            Error = "Title is required.";
            return;
        }

        Error = null;
        IsSaving = true;
        try
        {
            await OnSave.InvokeAsync((Title.Trim(), Assignee.Trim(), Priority, DueDate));
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            Error = ex.Message;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        Error = null;
    }
}

@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @TotalCount</div>
    <div><strong>To Do:</strong> @ToDoCount</div>
    <div><strong>In Progress:</strong> @InProgressCount</div>
    <div><strong>Done:</strong> @DoneCount</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int ToDoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async System.Threading.Tasks.Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveRequested="(dir) => HandleMoveAsync(task.Id, dir)" />
            }
            <AddTaskForm OnSave="HandleAddAsync" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskAdded { get; set; }

    private async System.Threading.Tasks.Task HandleMoveAsync(int taskId, string direction)
    {
        await OnTaskMoved.InvokeAsync((taskId, direction));
    }

    private async System.Threading.Tasks.Task HandleAddAsync((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskAdded.InvokeAsync(data);
    }
}

@page "/board"
@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                ToDoCount="todoCounts"
                InProgressCount="inProgressCounts"
                DoneCount="doneCounts"
                OverdueCount="overdueCounts" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    // Unfiltered counts for the stats bar
    private int todoCounts => allTasks.Count(t => t.Status == "To Do");
    private int inProgressCounts => allTasks.Count(t => t.Status == "In Progress");
    private int doneCounts => allTasks.Count(t => t.Status == "Done");
    private int overdueCounts => allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    // Filtered lists for columns
    private List<TaskItem> filteredToDo => FilterByStatus("To Do");
    private List<TaskItem> filteredInProgress => FilterByStatus("In Progress");
    private List<TaskItem> filteredDone => FilterByStatus("Done");

    private List<TaskItem> FilterByStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMovedAsync((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Replace the task in the list with updated status
            var idx = allTasks.FindIndex(t => t.Id == task.Id);
            if (idx >= 0)
            {
                allTasks[idx] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskAddedAsync(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
        // CreateTaskAsync returns a task with default status; override to match the column
        allTasks.Add(created with { Status = status });
    }
}

