                       @bind="Title" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                       @bind="Assignee" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="SaveAsync" disabled="@IsSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
