        IsSaving = true;
        try
        {
            await OnSave.InvokeAsync((Title.Trim(), Assignee.Trim(), Priority, DueDate));
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            Error = ex.Message;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        Error = null;
    }
}

