@page "/board"
@namespace sv_cb493d549a4f46a1819f89caaafb804d.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                ToDoCount="todoCounts"
                InProgressCount="inProgressCounts"
                DoneCount="doneCounts"
                OverdueCount="overdueCounts" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, &quot;To Do&quot;)" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, &quot;In Progress&quot;)" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnTaskMoved="HandleTaskMovedAsync"
                     OnTaskAdded="(data) => HandleTaskAddedAsync(data, &quot;Done&quot;)" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    // Unfiltered counts for the stats bar
    private int todoCounts => allTasks.Count(t => t.Status == "To Do");
    private int inProgressCounts => allTasks.Count(t => t.Status == "In Progress");
    private int doneCounts => allTasks.Count(t => t.Status == "Done");
    private int overdueCounts => allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    // Filtered lists for columns
    private List<TaskItem> filteredToDo => FilterByStatus("To Do");
    private List<TaskItem> filteredInProgress => FilterByStatus("In Progress");
    private List<TaskItem> filteredDone => FilterByStatus("Done");

    private List<TaskItem> FilterByStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMovedAsync((int TaskId, string Direction) move)
    {
        var task = allTasks.FirstOrDefault(t => t.Id == move.TaskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(Statuses, task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= Statuses.Length) return;

        var newStatus = Statuses[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == task.Id);
            if (idx >= 0)
            {
                allTasks[idx] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskAddedAsync(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

